    return null;
}

static string ResolveSecretOrLiteral(string raw, JsonElement? secrets)
{
    if (raw.StartsWith("{secret:", StringComparison.Ordinal) && raw.EndsWith('}'))
    {
        var key = raw[8..^1];
        if (secrets is { } root && root.TryGetProperty(key, out var value) && value.GetString() is { } s)
        {
            return s;
        }
        throw new AuthResolutionException($"secrets.json has no value for \"{key}\" (referenced by auth.json).");
    }
    return raw;
}

static string GetProp(JsonElement el, string name) => el.TryGetProperty(name, out var v) ? v.GetString() ?? "" : "";

static async Task<(int ExitCode, string Stdout, string Stderr)> RunScriptCommandAsync(string command, string skillRoot)
{
    var psi = new ProcessStartInfo
    {
        RedirectStandardOutput = true,
        RedirectStandardError = true,
        UseShellExecute = false,
        WorkingDirectory = skillRoot,
    };
    if (OperatingSystem.IsWindows())
    {
        psi.FileName = "cmd.exe";
        psi.ArgumentList.Add("/c");
        psi.ArgumentList.Add(command);
    }
    else
    {
        psi.FileName = "/bin/sh";
        psi.ArgumentList.Add("-c");
        psi.ArgumentList.Add(command);
    }
    using var process = Process.Start(psi)!;
    var stdoutTask = process.StandardOutput.ReadToEndAsync();
    var stderrTask = process.StandardError.ReadToEndAsync();
    await process.WaitForExitAsync();
    return (process.ExitCode, await stdoutTask, await stderrTask);
}

static async Task ApplyExplicitProfileAsync(HttpClient http, JsonElement profile, string profileName, JsonElement? secrets, List<string> query, List<(string Name, string Value)> headers, [CallerFilePath] string callerPath = "")
{
    var type = GetProp(profile, "type");
    switch (type)
    {
        case "bearer":
        {
            var token = ResolveSecretOrLiteral(GetProp(profile, "token"), secrets);
            var value = token.StartsWith("Bearer ", StringComparison.OrdinalIgnoreCase) ? token : $"Bearer {token}";
            headers.Add(("Authorization", value));
            break;
        }
        case "basic":
        {
            var user = ResolveSecretOrLiteral(GetProp(profile, "username"), secrets);
            var pass = ResolveSecretOrLiteral(GetProp(profile, "password"), secrets);
            var encoded = Convert.ToBase64String(Encoding.UTF8.GetBytes($"{user}:{pass}"));
            headers.Add(("Authorization", $"Basic {encoded}"));
            break;
        }
        case "custom":
        {
            if (profile.TryGetProperty("headers", out var headersEl) && headersEl.ValueKind == JsonValueKind.Array)
            {
                foreach (var h in headersEl.EnumerateArray())
                {
                    var name = GetProp(h, "name");
                    var value = ResolveSecretOrLiteral(GetProp(h, "value"), secrets);
                    headers.Add((name, value));
                }
            }
            break;
        }
        case "oauth2":
        {
            var accessToken = await ResolveOAuthAccessTokenAsync(http, profile, profileName, secrets);
            headers.Add(("Authorization", $"Bearer {accessToken}"));
            break;
        }
        case "script":
        {
            var command = GetProp(profile, "command");
            var headerName = GetProp(profile, "header");
            if (string.IsNullOrEmpty(headerName)) headerName = "Authorization";
            var bearerPrefix = profile.TryGetProperty("bearerPrefix", out var bpEl) && bpEl.ValueKind == JsonValueKind.True;
            var scriptDir = Path.GetDirectoryName(callerPath) ?? ".";
            var skillRoot = Path.GetFullPath(Path.Combine(scriptDir, ".."));
            var (exitCode, stdout, stderr) = await RunScriptCommandAsync(command, skillRoot);
            if (exitCode != 0)
                throw new AuthResolutionException($"Script command for auth profile '{profileName}' exited with code {exitCode}: {stderr.Trim()}");
            var token = stdout.Trim();
            if (bearerPrefix && !token.StartsWith("Bearer ", StringComparison.OrdinalIgnoreCase))
                token = $"Bearer {token}";
            headers.Add((headerName, token));
            break;
        }
        default:
            throw new AuthResolutionException($"Auth profile type '{type}' is not supported by this generated dispatcher yet.");
    }
}

static (string Verifier, string Challenge) GeneratePkce()
{
    var bytes = new byte[32];
    RandomNumberGenerator.Fill(bytes);
    var verifier = Convert.ToBase64String(bytes).TrimEnd('=').Replace('+', '-').Replace('/', '_');
    var challengeBytes = SHA256.HashData(Encoding.ASCII.GetBytes(verifier));
    var challenge = Convert.ToBase64String(challengeBytes).TrimEnd('=').Replace('+', '-').Replace('/', '_');
    return (verifier, challenge);
}

static string GenerateState()
{
    var bytes = new byte[16];
    RandomNumberGenerator.Fill(bytes);
    return Convert.ToBase64String(bytes).TrimEnd('=').Replace('+', '-').Replace('/', '_');
}

static Dictionary<string, string> ParseQuery(string query)
{
    var result = new Dictionary<string, string>(StringComparer.Ordinal);
    var q = query.TrimStart('?');
    if (q.Length == 0) return result;
    foreach (var pair in q.Split('&'))
    {
        var idx = pair.IndexOf('=');
        if (idx < 0) { result[Uri.UnescapeDataString(pair)] = ""; continue; }
        result[Uri.UnescapeDataString(pair[..idx])] = Uri.UnescapeDataString(pair[(idx + 1)..]);
    }
    return result;
}

static bool TryLaunchBrowser(string url)
{
    try { Process.Start(new ProcessStartInfo(url) { UseShellExecute = true }); return true; }
    catch
    {
        try
        {
            if (OperatingSystem.IsMacOS()) { Process.Start("open", url); return true; }
            if (OperatingSystem.IsLinux()) { Process.Start("xdg-open", url); return true; }
            if (OperatingSystem.IsWindows()) { Process.Start(new ProcessStartInfo("cmd", $"/c start {url}") { CreateNoWindow = true }); return true; }
        }
        catch { }
        return false;
    }
}

static bool RunClipboardCommand(string fileName, string[] args, string text)
{
    try
    {
        var psi = new ProcessStartInfo(fileName) { RedirectStandardInput = true, UseShellExecute = false, CreateNoWindow = true };
        foreach (var a in args) psi.ArgumentList.Add(a);
        using var process = Process.Start(psi);
        if (process is null) return false;
        process.StandardInput.Write(text);
        process.StandardInput.Close();
        process.WaitForExit();
        return process.ExitCode == 0;
    }
    catch
    {
        return false;
    }
}

static bool TryCopyToClipboard(string text)
{
    if (OperatingSystem.IsMacOS()) return RunClipboardCommand("pbcopy", Array.Empty<string>(), text);
    if (OperatingSystem.IsWindows()) return RunClipboardCommand("clip", Array.Empty<string>(), text);
    if (OperatingSystem.IsLinux())
    {
        return RunClipboardCommand("wl-copy", Array.Empty<string>(), text)
            || RunClipboardCommand("xclip", new[] { "-selection", "clipboard" }, text)
            || RunClipboardCommand("xsel", new[] { "--clipboard", "--input" }, text);
    }
    return false;
}

static void AddCallbackPrefixes(HttpListener listener, Uri uri)
{
    var scheme = uri.Scheme;
    var port = uri.Port;
    var host = uri.Host;
    listener.Prefixes.Add($"{scheme}://{host}:{port}/");
    if (host.Equals("localhost", StringComparison.OrdinalIgnoreCase))
        listener.Prefixes.Add($"{scheme}://127.0.0.1:{port}/");
    else if (host is "127.0.0.1" or "::1")
        listener.Prefixes.Add($"{scheme}://localhost:{port}/");
}

static HttpListener BeginCallbackListener(string callbackUrl)
{
    var uri = new Uri(callbackUrl);
    var listener = new HttpListener();
    AddCallbackPrefixes(listener, uri);
    try
    {
        listener.Start();
    }
    catch (HttpListenerException ex)
    {
        throw new AuthResolutionException($"Could not start the local OAuth callback listener on {uri.Host}:{uri.Port} ({ex.Message}). Another process may be using this port \u2014 try a different callbackUrl in auth.json.");
    }
    return listener;
}

static async Task<Dictionary<string, string>> AwaitOAuthCallbackAsync(HttpListener listener)
{
  try
  {
    while (true)
    {
        var context = await listener.GetContextAsync();
        var result = ParseQuery(context.Request.Url?.Query ?? "");
        if (result.ContainsKey("code") || result.ContainsKey("error"))
        {
            var page = Encoding.UTF8.GetBytes("<html><body>Login complete \u2014 you can close this window and return to the terminal.</body></html>");
            context.Response.StatusCode = 200;
            context.Response.ContentType = "text/html; charset=utf-8";
            context.Response.ContentLength64 = page.Length;
            context.Response.OutputStream.Write(page, 0, page.Length);
            context.Response.Close();
            return result;
        }
        context.Response.StatusCode = 404;
        context.Response.Close();
    }
  }
  finally
  {
      listener.Stop();
      listener.Close();
  }
}

static (string? AuthUrl, string? TokenUrl, List<string> Scopes) ResolveOAuthEndpoints(JsonElement profile)
{
    var preset = GetProp(profile, "preset");
    var tenant = GetProp(profile, "tenant");
    string? authUrl = profile.TryGetProperty("authUrl", out var a) ? a.GetString() : null;
    string? tokenUrl = profile.TryGetProperty("tokenUrl", out var t) ? t.GetString() : null;
    var scopes = new List<string>();
    if (profile.TryGetProperty("scopes", out var scopesEl) && scopesEl.ValueKind == JsonValueKind.Array)
    {
        foreach (var s in scopesEl.EnumerateArray()) { if (s.GetString() is { } sv) scopes.Add(sv); }
    }
    if (string.Equals(preset, "entra", StringComparison.OrdinalIgnoreCase))
    {
        authUrl ??= tenant.Length > 0 ? $"https://login.microsoftonline.com/{tenant}/oauth2/v2.0/authorize" : null;
        tokenUrl ??= tenant.Length > 0 ? $"https://login.microsoftonline.com/{tenant}/oauth2/v2.0/token" : null;
        if (!scopes.Contains("offline_access", StringComparer.Ordinal)) scopes.Add("offline_access");
    }
    return (authUrl, tokenUrl, scopes);
}

static string BuildAuthorizeUrl(string authUrl, string clientId, string callbackUrl, List<string> scopes, string challenge, string state, JsonElement profile)
{
    var qs = new List<string>
    {
        "response_type=code",
        $"client_id={Uri.EscapeDataString(clientId)}",
        $"redirect_uri={Uri.EscapeDataString(callbackUrl)}",
        $"code_challenge={Uri.EscapeDataString(challenge)}",
        "code_challenge_method=S256",
        $"state={Uri.EscapeDataString(state)}",
    };
    if (scopes.Count > 0) qs.Add($"scope={Uri.EscapeDataString(string.Join(' ', scopes))}");
    if (profile.TryGetProperty("authorizeRequest", out var arEl) && arEl.TryGetProperty("body", out var bodyEl) && bodyEl.ValueKind == JsonValueKind.Object)
    {
        // authorizeRequest.headers has no effect here: there is no way to attach custom HTTP
        // headers to a browser navigation, only extra parameters on the URL itself.
        foreach (var prop in bodyEl.EnumerateObject())
        {
            qs.Add($"{Uri.EscapeDataString(prop.Name)}={Uri.EscapeDataString(prop.Value.GetString() ?? "")}");
        }
    }
    var sep = authUrl.Contains('?') ? "&" : "?";
    return authUrl + sep + string.Join("&", qs);
}

static string? SecretValue(JsonElement? secrets, string schemeId, string key)
{
    if (secrets is not { } root) return null;
    if (!root.TryGetProperty(schemeId, out var entry)) return null;
    return entry.TryGetProperty(key, out var value) ? value.GetString() : null;
}

static async Task ApplyAuthAsync(HttpClient http, SchemeSpec scheme, JsonElement? secrets, List<string> query, List<(string Name, string Value)> headers, Dictionary<string, string> oauthTokenCache)
{
    switch (scheme.Kind)
    {
        case "apiKey":
        {
            var key = SecretValue(secrets, scheme.Id, "apiKey");
            if (key is null) { Console.Error.WriteLine($"warning: no apiKey configured for scheme '{scheme.Id}' in secrets.json — sending unauthenticated."); break; }
            if (scheme.ApiKeyLocation == "query") query.Add($"{Uri.EscapeDataString(scheme.ApiKeyName!)}={Uri.EscapeDataString(key)}");
            else headers.Add((scheme.ApiKeyName!, key));
            break;
        }
        case "bearer":
        {
            var token = SecretValue(secrets, scheme.Id, "bearerToken");
            if (token is null) { Console.Error.WriteLine($"warning: no bearerToken configured for scheme '{scheme.Id}' in secrets.json — sending unauthenticated."); break; }
            headers.Add(("Authorization", $"Bearer {token}"));
            break;
        }
        case "basic":
        {
            var user = SecretValue(secrets, scheme.Id, "username");
            var pass = SecretValue(secrets, scheme.Id, "password");
            if (user is null || pass is null) { Console.Error.WriteLine($"warning: no username/password configured for scheme '{scheme.Id}' in secrets.json — sending unauthenticated."); break; }
            var encoded = Convert.ToBase64String(Encoding.UTF8.GetBytes($"{user}:{pass}"));
            headers.Add(("Authorization", $"Basic {encoded}"));
            break;
        }
        case "oauth2":
        {
            var clientId = SecretValue(secrets, scheme.Id, "clientId");
            var clientSecret = SecretValue(secrets, scheme.Id, "clientSecret");
            var tokenUrl = SecretValue(secrets, scheme.Id, "tokenUrl") ?? scheme.OAuthTokenUrl;
            if (clientId is null || clientSecret is null || tokenUrl is null) { Console.Error.WriteLine($"warning: no clientId/clientSecret/tokenUrl configured for scheme '{scheme.Id}' in secrets.json — sending unauthenticated."); break; }
            var token = await FetchOAuth2TokenAsync(http, tokenUrl, clientId, clientSecret, oauthTokenCache);
            if (token is null) { Console.Error.WriteLine($"warning: failed to obtain an OAuth2 token for scheme '{scheme.Id}' — sending unauthenticated."); break; }
            headers.Add(("Authorization", $"Bearer {token}"));
            break;
        }
        default:
            Console.Error.WriteLine($"warning: scheme '{scheme.Id}' ({scheme.Kind}) is not a supported auth kind — sending unauthenticated.");
            break;
    }
}

static async Task<string?> FetchOAuth2TokenAsync(HttpClient http, string tokenUrl, string clientId, string clientSecret, Dictionary<string, string> tokenCache)
{
    // Cached in memory for this process run only — never written to disk.
    var cacheKey = tokenUrl + "|" + clientId;
    if (tokenCache.TryGetValue(cacheKey, out var cached))
    {
        return cached;
    }
    var form = new FormUrlEncodedContent(new Dictionary<string, string>
    {
        ["grant_type"] = "client_credentials",
        ["client_id"] = clientId,
        ["client_secret"] = clientSecret,
    });
    using var response = await http.PostAsync(tokenUrl, form);
    if (!response.IsSuccessStatusCode)
    {
        return null;
    }
    try
    {
        using var doc = JsonDocument.Parse(await response.Content.ReadAsStringAsync());
        if (!doc.RootElement.TryGetProperty("access_token", out var tokenEl))
        {
            return null;
        }
        var token = tokenEl.GetString();
        if (token is not null)
        {
            tokenCache[cacheKey] = token;
        }
        return token;
    }
    catch (JsonException)
    {
        // The token endpoint returned a 2xx with a body that isn't valid JSON — treat
        // the same as a failed token fetch rather than crashing the whole dispatch.
        return null;
    }
}

static async Task<(string AccessToken, string? RefreshToken, int ExpiresIn, string? IdToken)?> PostTokenRequestAsync(HttpClient http, JsonElement profile, string tokenUrl, string clientId, Dictionary<string, string> form, JsonElement? secrets)
{
    var clientAuth = GetProp(profile, "clientAuth");
    var clientSecretRaw = profile.TryGetProperty("clientSecret", out var csEl) ? csEl.GetString() : null;
    var clientSecret = clientSecretRaw is { Length: > 0 } ? ResolveSecretOrLiteral(clientSecretRaw, secrets) : null;

    using var request = new HttpRequestMessage(HttpMethod.Post, tokenUrl);
    if (clientAuth == "basic" && clientSecret is not null)
    {
        form.Remove("client_id");
        var basic = Convert.ToBase64String(Encoding.UTF8.GetBytes($"{clientId}:{clientSecret}"));
        request.Headers.TryAddWithoutValidation("Authorization", $"Basic {basic}");
    }
    else if (clientSecret is not null)
    {
        form["client_secret"] = clientSecret;
    }

    if (profile.TryGetProperty("tokenRequest", out var trEl))
    {
        if (trEl.TryGetProperty("headers", out var hEl) && hEl.ValueKind == JsonValueKind.Object)
        {
            foreach (var prop in hEl.EnumerateObject()) request.Headers.TryAddWithoutValidation(prop.Name, prop.Value.GetString() ?? "");
        }
        if (trEl.TryGetProperty("body", out var bEl) && bEl.ValueKind == JsonValueKind.Object)
        {
            foreach (var prop in bEl.EnumerateObject()) form[prop.Name] = prop.Value.GetString() ?? "";
        }
    }

    request.Content = new FormUrlEncodedContent(form);
    using var response = await http.SendAsync(request);
    var text = await response.Content.ReadAsStringAsync();
    if (!response.IsSuccessStatusCode) return null;
    try
    {
        using var doc = JsonDocument.Parse(text);
        var root = doc.RootElement;
        var preferred = profile.TryGetProperty("tokenField", out var tfEl) && tfEl.GetString() is { Length: > 0 } tf ? tf : "access_token";
        var other = preferred == "id_token" ? "access_token" : "id_token";
        string? ReadField(string name) => root.TryGetProperty(name, out var el) ? el.GetString() : null;
        var accessToken = ReadField(preferred);
        if (accessToken is null)
        {
            accessToken = ReadField(other);
            if (accessToken is not null)
            {
                Console.Error.WriteLine($"warning: token response missing '{preferred}'; using '{other}' instead.");
            }
        }
        if (accessToken is null) return null;
        var refreshToken = ReadField("refresh_token");
        var idToken = ReadField("id_token");
        var expiresIn = root.TryGetProperty("expires_in", out var eiEl) && eiEl.TryGetInt32(out var ei) ? ei : 3600;
        return (accessToken, refreshToken, expiresIn, idToken);
    }
    catch (JsonException)
    {
        return null;
    }
}

static Task<(string AccessToken, string? RefreshToken, int ExpiresIn, string? IdToken)?> ExchangeCodeForTokenAsync(HttpClient http, JsonElement profile, string tokenUrl, string clientId, string code, string verifier, string callbackUrl, JsonElement? secrets) =>
    PostTokenRequestAsync(http, profile, tokenUrl, clientId, new Dictionary<string, string> { ["grant_type"] = "authorization_code", ["code"] = code, ["redirect_uri"] = callbackUrl, ["code_verifier"] = verifier, ["client_id"] = clientId }, secrets);

static Task<(string AccessToken, string? RefreshToken, int ExpiresIn, string? IdToken)?> FetchClientCredentialsTokenAsync(HttpClient http, JsonElement profile, string tokenUrl, string clientId, JsonElement? secrets) =>
    PostTokenRequestAsync(http, profile, tokenUrl, clientId, new Dictionary<string, string> { ["grant_type"] = "client_credentials", ["client_id"] = clientId }, secrets);

static Task<(string AccessToken, string? RefreshToken, int ExpiresIn, string? IdToken)?> RefreshOAuthTokenAsync(HttpClient http, JsonElement profile, string tokenUrl, string clientId, string refreshToken, JsonElement? secrets) =>
    PostTokenRequestAsync(http, profile, tokenUrl, clientId, new Dictionary<string, string> { ["grant_type"] = "refresh_token", ["refresh_token"] = refreshToken, ["client_id"] = clientId }, secrets);

static string TokenCachePath([CallerFilePath] string callerPath = "")
{
    var scriptDir = Path.GetDirectoryName(callerPath) ?? ".";
    return Path.Combine(scriptDir, "..", ".auth-cache.json");
}

static async Task<Dictionary<string, JsonElement>> ReadTokenCacheAsync(string path)
{
    var result = new Dictionary<string, JsonElement>(StringComparer.Ordinal);
    if (!File.Exists(path)) return result;
    try
    {
        using var doc = JsonDocument.Parse(await File.ReadAllTextAsync(path));
        foreach (var prop in doc.RootElement.EnumerateObject()) result[prop.Name] = prop.Value.Clone();
    }
    catch (JsonException) { }
    return result;
}

static async Task WriteTokenCacheAsync(string path, Dictionary<string, JsonElement> cache)
{
    var obj = new JsonObject();
    foreach (var (key, value) in cache) obj[key] = JsonNode.Parse(value.GetRawText());
    var tmpPath = path + ".tmp-" + Guid.NewGuid().ToString("N");
    await File.WriteAllTextAsync(tmpPath, obj.ToJsonString(new JsonSerializerOptions { WriteIndented = true }));
    if (!OperatingSystem.IsWindows())
    {
        File.SetUnixFileMode(tmpPath, UnixFileMode.UserRead | UnixFileMode.UserWrite);
    }
    File.Move(tmpPath, path, overwrite: true);
}

static void StoreTokenInCache(Dictionary<string, JsonElement> cache, string profileName, (string AccessToken, string? RefreshToken, int ExpiresIn, string? IdToken) token)
{
    var obj = new JsonObject { ["access_token"] = token.AccessToken, ["expires_at"] = DateTimeOffset.UtcNow.AddSeconds(token.ExpiresIn).ToString("o") };
    if (token.RefreshToken is not null) obj["refresh_token"] = token.RefreshToken;
    if (token.IdToken is not null) obj["id_token"] = token.IdToken;
    cache[profileName] = JsonDocument.Parse(obj.ToJsonString()).RootElement.Clone();
}

static async Task<T> WithTokenCacheLockAsync<T>(Func<Task<T>> action)
{
    var lockPath = TokenCachePath() + ".lock";
    FileStream? lockStream = null;
    for (var attempt = 0; attempt < 100 && lockStream is null; attempt++)
    {
        try { lockStream = new FileStream(lockPath, FileMode.OpenOrCreate, FileAccess.ReadWrite, FileShare.None); }
        catch (IOException) { await Task.Delay(50); }
    }
    if (lockStream is null)
    {
        throw new AuthResolutionException("Could not acquire the token cache lock (.auth-cache.json.lock) after multiple attempts \u2014 another process may be stuck holding it.");
    }
    try { return await action(); }
    finally { lockStream.Dispose(); }
}

static async Task<string> ResolveOAuthAccessTokenAsync(HttpClient http, JsonElement profile, string profileName, JsonElement? secrets)
{
    var (_, tokenUrl, _) = ResolveOAuthEndpoints(profile);
    if (tokenUrl is null) throw new AuthResolutionException($"Auth profile '{profileName}' (oauth2) has no tokenUrl configured (directly or via a preset).");
    var clientId = ResolveSecretOrLiteral(GetProp(profile, "clientId"), secrets);
    var grant = GetProp(profile, "grant");
    var cachePath = TokenCachePath();

    return await WithTokenCacheLockAsync(async () =>
    {
        var cache = await ReadTokenCacheAsync(cachePath);
        if (cache.TryGetValue(profileName, out var entry))
        {
            var expiresAt = entry.TryGetProperty("expires_at", out var eaEl) && DateTimeOffset.TryParse(eaEl.GetString(), out var ea) ? ea : DateTimeOffset.MinValue;
            var cachedToken = entry.TryGetProperty("access_token", out var atEl) ? atEl.GetString() : null;
            if (cachedToken is not null && expiresAt > DateTimeOffset.UtcNow.AddSeconds(30))
            {
                return cachedToken;
            }
            var refreshToken = entry.TryGetProperty("refresh_token", out var rtEl) ? rtEl.GetString() : null;
            if (refreshToken is not null)
            {
                var refreshed = await RefreshOAuthTokenAsync(http, profile, tokenUrl, clientId, refreshToken, secrets);
                if (refreshed is not null)
                {
                    StoreTokenInCache(cache, profileName, refreshed.Value);
                    await WriteTokenCacheAsync(cachePath, cache);
                    return refreshed.Value.AccessToken;
                }
            }
        }

        if (grant == "client_credentials")
        {
            var fetched = await FetchClientCredentialsTokenAsync(http, profile, tokenUrl, clientId, secrets);
            if (fetched is not null)
            {
                StoreTokenInCache(cache, profileName, fetched.Value);
                await WriteTokenCacheAsync(cachePath, cache);
                return fetched.Value.AccessToken;
            }
            throw new AuthResolutionException($"Failed to obtain a client_credentials token for auth profile '{profileName}'.");
        }

        throw new AuthResolutionException($"No valid or refreshable token for auth profile '{profileName}'. Run: dotnet run scripts/call.cs -- login {profileName}");
    });
}

static Process? TryStartOAuthCaptureProcess(string callbackUrl, string state)
{
    try
    {
        var psi = new ProcessStartInfo
        {
            FileName = "api2skill",
            RedirectStandardOutput = true,
            RedirectStandardError = true,
            UseShellExecute = false,
        };
        psi.ArgumentList.Add("oauth-capture");
        psi.ArgumentList.Add("--callback-url");
        psi.ArgumentList.Add(callbackUrl);
        psi.ArgumentList.Add("--state");
        psi.ArgumentList.Add(state);
        psi.ArgumentList.Add("--json");
        var process = Process.Start(psi);
        if (process is null) return null;
        // Old/wrong binaries exit immediately — treat as missing so HTTP can fall back.
        process.WaitForExit(150);
        if (process.HasExited)
        {
            process.Dispose();
            return null;
        }
        return process;
    }
    catch (Exception)
    {
        return null;
    }
}

static bool IsHttpLoopbackCallback(string callbackUrl)
{
    if (!Uri.TryCreate(callbackUrl, UriKind.Absolute, out var uri)) return false;
    if (!uri.Scheme.Equals("http", StringComparison.OrdinalIgnoreCase)) return false;
    return uri.Host.Equals("localhost", StringComparison.OrdinalIgnoreCase)
        || uri.Host is "127.0.0.1" or "::1" or "[::1]";
}

static async Task<Dictionary<string, string>> AwaitOAuthCaptureProcessAsync(Process process)
{
    var stdout = await process.StandardOutput.ReadToEndAsync();
    await process.WaitForExitAsync();
    var line = stdout.Trim();
    if (line.Length == 0)
        throw new AuthResolutionException($"api2skill oauth-capture exited {process.ExitCode} with empty stdout.");
    try
    {
        using var doc = JsonDocument.Parse(line);
        var root = doc.RootElement;
        var result = new Dictionary<string, string>(StringComparer.Ordinal);
        if (root.TryGetProperty("code", out var codeEl) && codeEl.GetString() is { } code) result["code"] = code;
        if (root.TryGetProperty("state", out var stateEl) && stateEl.GetString() is { } st) result["state"] = st;
        if (root.TryGetProperty("error", out var errEl) && errEl.GetString() is { } err) result["error"] = err;
        if (root.TryGetProperty("errorDescription", out var edEl) && edEl.GetString() is { } ed) result["error_description"] = ed;
        var ok = root.TryGetProperty("ok", out var okEl) && okEl.ValueKind == JsonValueKind.True;
        if (!ok && !result.ContainsKey("code"))
            throw new AuthResolutionException(result.TryGetValue("error", out var e) ? e : "oauth-capture failed");
        return result;
    }
    catch (JsonException ex)
    {
        throw new AuthResolutionException($"Failed to parse oauth-capture JSON: {ex.Message}");
    }
}

static void PresentAuthorizeUrl(string profileName, string authorizeUrl, string browserLaunch)
{
    if (browserLaunch == "clipboard")
    {
        var copied = TryCopyToClipboard(authorizeUrl);
        Console.WriteLine(copied
            ? $"Copied the sign-in URL to your clipboard for profile '{profileName}'. Paste it into your browser:"
            : $"Could not copy the sign-in URL to the clipboard automatically. Open this URL to sign in for profile '{profileName}':");
        Console.WriteLine(authorizeUrl);
        return;
    }
    Console.WriteLine($"Opening your browser to sign in for profile '{profileName}'...");
    var browserLaunched = TryLaunchBrowser(authorizeUrl);
    Console.WriteLine(browserLaunched
        ? "If it did not open, visit this URL to sign in:"
        : "Could not launch a browser automatically. Open this URL to sign in:");
    Console.WriteLine(authorizeUrl);
}

static async Task<int> LoginAsync(string profileName)
{
    var authConfig = LoadAuthConfig();
    var profiles = authConfig is { } cfg && cfg.TryGetProperty("profiles", out var profilesEl) ? profilesEl : (JsonElement?)null;
    var profile = FindProfile(profiles, profileName);
    if (profile is null)
    {
        Console.Error.WriteLine($"No auth profile named '{profileName}' in auth.json.");
        return 2;
    }
    var type = GetProp(profile.Value, "type");
    if (type != "oauth2")
    {
        Console.Error.WriteLine($"Profile '{profileName}' is type '{type}', not 'oauth2' \u2014 login is only applicable to oauth2 profiles.");
        return 2;
    }
    var grant = GetProp(profile.Value, "grant");
    if (grant == "client_credentials")
    {
        Console.WriteLine($"Profile '{profileName}' uses client_credentials \u2014 not applicable: no interactive login is needed, a token is obtained automatically at call time.");
        return 0;
    }

    var (authUrl, tokenUrl, scopes) = ResolveOAuthEndpoints(profile.Value);
    if (authUrl is null || tokenUrl is null)
    {
        Console.Error.WriteLine($"Profile '{profileName}' is missing authUrl/tokenUrl (directly or via a preset).");
        return 2;
    }
    var callbackUrl = GetProp(profile.Value, "callbackUrl");
    if (callbackUrl.Length == 0) callbackUrl = "http://localhost:8400/callback";
    var secrets = LoadSecrets();
    var clientId = ResolveSecretOrLiteral(GetProp(profile.Value, "clientId"), secrets);

    var (verifier, challenge) = GeneratePkce();
    var state = GenerateState();
    var authorizeUrl = BuildAuthorizeUrl(authUrl, clientId, callbackUrl, scopes, challenge, state, profile.Value);

    // Prefer app-owned capture (api2skill oauth-capture). HTTP HttpListener is fallback only.
    var captureProc = TryStartOAuthCaptureProcess(callbackUrl, state);
    Dictionary<string, string> callbackParams;
    if (captureProc is not null)
    {
        Console.WriteLine($"Listening for OAuth callback on {callbackUrl} ...");
        await Task.Delay(200);
        PresentAuthorizeUrl(profileName, authorizeUrl, GetProp(profile.Value, "browserLaunch"));
        try { callbackParams = await AwaitOAuthCaptureProcessAsync(captureProc); }
        catch (AuthResolutionException ex) { Console.Error.WriteLine(ex.Message); return 2; }
        finally { captureProc.Dispose(); }
    }
    else if (IsHttpLoopbackCallback(callbackUrl))
    {
        HttpListener callbackListener;
        try { callbackListener = BeginCallbackListener(callbackUrl); }
        catch (AuthResolutionException ex) { Console.Error.WriteLine(ex.Message); return 2; }
        Console.WriteLine($"Listening for OAuth callback on {callbackUrl} ...");
        PresentAuthorizeUrl(profileName, authorizeUrl, GetProp(profile.Value, "browserLaunch"));
        try { callbackParams = await AwaitOAuthCallbackAsync(callbackListener); }
        catch (AuthResolutionException ex) { Console.Error.WriteLine(ex.Message); return 2; }
    }
    else
    {
        Console.Error.WriteLine("Could not start 'api2skill oauth-capture'. Install or upgrade api2skill and ensure it is on PATH. HTTPS / custom-scheme / hosted callbacks require the tool (HTTP loopback can fall back to an in-script listener).");
        return 2;
    }

    if (!callbackParams.TryGetValue("state", out var returnedState) || returnedState != state)
    {
        Console.Error.WriteLine("The callback's state did not match what was sent \u2014 rejecting (possible CSRF/mix-up). No token was stored. Run login again.");
        return 2;
    }
    if (!callbackParams.TryGetValue("code", out var code))
    {
        var err = callbackParams.TryGetValue("error", out var e) ? e : "no authorization code was returned";
        Console.Error.WriteLine($"Login failed: {err}");
        return 2;
    }

    using var http = new HttpClient();
    var tokenResponse = await ExchangeCodeForTokenAsync(http, profile.Value, tokenUrl, clientId, code, verifier, callbackUrl, secrets);
    if (tokenResponse is null)
    {
        Console.Error.WriteLine("Failed to exchange the authorization code for a token.");
        return 2;
    }

    await WithTokenCacheLockAsync(async () =>
    {
        var cachePath = TokenCachePath();
        var cache = await ReadTokenCacheAsync(cachePath);
        StoreTokenInCache(cache, profileName, tokenResponse.Value);
        await WriteTokenCacheAsync(cachePath, cache);
        return true;
    });

    Console.WriteLine($"Login succeeded for profile '{profileName}'. You can now call operations that use it.");
    return 0;
}

static (Dictionary<string, string> Params, string? Body) ParseArgs(string[] rest)
{
    var values = new Dictionary<string, string>(StringComparer.Ordinal);
    string? body = null;
    for (var i = 0; i < rest.Length; i++)
    {
        if (!rest[i].StartsWith("--", StringComparison.Ordinal) || i + 1 >= rest.Length)
        {
            continue;
        }
        var key = rest[i][2..];
        var value = rest[++i];
        if (key == "body") { body = value; } else { values[key] = value; }
    }
    return (values, body);
}

